var minimumDistance = function(nums) {
    const pos = new Map();
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        if (!pos.has(v)) pos.set(v, []);
        pos.get(v).push(i);
    }
    let best = null;
    for (const ids of pos.values()) {
        for (let t = 0; t + 2 < ids.length; t++) {
            const span = 2 * (ids[t + 2] - ids[t]);
            if (best === null || span < best) best = span;
        }
    }
    return best === null ? -1 : best;
};
